// We assert that this generic element is specifically a Canvas
let myCanvas = document.getElementById('my-canvas') as HTMLCanvasElement;

// Now TS auto-completes canvas-specific properties!
myCanvas.getContext('2d');

interface User { name: string; age: number; }

// We are LYING to the compiler here. This object is missing 'age'.
// But because we used 'as User', TS forcefully ignores the error.
const fakeUser = { name: "Alice" } as User;

console.log(fakeUser.age); // Undefined! Runtime crash risk!
